// CHECK-NEXT:    store <16 x i8> [[TMP15]], ptr [[U_I3]], align 16
// CHECK-NEXT:    [[HIGH_I4:%.*]] = getelementptr inbounds nuw [[STRUCT_ANON_7:%.*]], ptr [[U_I3]], i32 0, i32 1
// CHECK-NEXT:    [[TMP16:%.*]] = load <8 x i8>, ptr [[HIGH_I4]], align 8
// CHECK-NEXT:    [[TMP17:%.*]] = load ptr, ptr [[PTR_ADDR_I1]], align 4
// CHECK-NEXT:    [[TMP18:%.*]] = load i32, ptr [[IMM_ADDR_I2]], align 4
// CHECK-NEXT:    [[HIGH1_I:%.*]] = getelementptr inbounds nuw [[STRUCT_ANON_7]], ptr [[U_I3]], i32 0, i32 1
// CHECK-NEXT:    [[TMP19:%.*]] = load <8 x i8>, ptr [[HIGH1_I]], align 8
// CHECK-NEXT:    [[TMP20:%.*]] = load ptr, ptr [[PTR_ADDR_I1]], align 4
// CHECK-NEXT:    [[TMP21:%.*]] = load i32, ptr [[IMM_ADDR_I2]], align 4
// CHECK-NEXT:    [[TMP22:%.*]] = call ptr @llvm.riscv.esp.vst.h.64.ip.m(<8 x i8> [[TMP19]], ptr [[TMP20]], i32 [[TMP21]])
// CHECK-NEXT:    ret void
//
void test_vld_h_64_ip(void *src, void *dst) {
    esp_vld_64_res_t ResH = esp_vld_h_64_ip_m(src, 8);
    // Convert 64-bit to 128-bit for store (high 64 bits)
    union {
        esp_vec128_t V128;
        struct {
            esp_vec64_t Low;
            esp_vec64_t High;
        } Parts;
    } U;
    U.Parts.Low = (esp_vec64_t){0,0,0,0,0,0,0,0};  // Zero low 64 bits
    U.Parts.High = ResH.Val;  // High 64 bits from load
    esp_vst_h_64_ip_m(U.V128, dst, 8);
}

