// CHECK-NEXT:    [[TMP19:%.*]] = load ptr, ptr [[PTR_ADDR_I1]], align 4
// CHECK-NEXT:    [[TMP20:%.*]] = load i32, ptr [[IMM_ADDR_I2]], align 4
// CHECK-NEXT:    [[TMP21:%.*]] = call ptr @llvm.riscv.esp.vst.l.64.ip.m(<8 x i8> [[TMP18]], ptr [[TMP19]], i32 [[TMP20]])
// CHECK-NEXT:    ret void
//
void test_vld_l_64_ip(void *src, void *dst) {
    esp_vld_64_res_t ResL = esp_vld_l_64_ip_m(src, 8);
    // Convert 64-bit to 128-bit for store (low 64 bits)
    union {
        esp_vec128_t V128;
        struct {
            esp_vec64_t Low;
            esp_vec64_t High;
        } Parts;
    } U;
    U.Parts.Low = ResL.Val;  // Low 64 bits from load
    U.Parts.High = (esp_vec64_t){0,0,0,0,0,0,0,0};  // Zero high 64 bits
    esp_vst_l_64_ip_m(U.V128, dst, 8);
}

